import{_ as a,c as l,o as e,a4 as i}from"./chunks/framework.HaEZziQ1.js";const q=JSON.parse('{"title":"浏览器端性能优化","description":"","frontmatter":{},"headers":[],"relativePath":"Document/前端性能优化专题/06_浏览器端性能优化.md","filePath":"Document/前端性能优化专题/06_浏览器端性能优化.md","lastUpdated":1709668918000}'),r={name:"Document/前端性能优化专题/06_浏览器端性能优化.md"},o=i('<h1 id="浏览器端性能优化" tabindex="-1">浏览器端性能优化 <a class="header-anchor" href="#浏览器端性能优化" aria-label="Permalink to &quot;浏览器端性能优化&quot;">​</a></h1><h2 id="规则1-把css-放在head-中加载" tabindex="-1">规则1：把CSS 放在HEAD 中加载 <a class="header-anchor" href="#规则1-把css-放在head-中加载" aria-label="Permalink to &quot;规则1：把CSS 放在HEAD 中加载&quot;">​</a></h2><ul><li>能让页面更早的开始渲染，避免闪屏</li><li>最好能包含关键渲染路径的样式：首屏</li></ul><h2 id="规则2-把js-放在body-末尾加载" tabindex="-1">规则2：把JS 放在BODY 末尾加载 <a class="header-anchor" href="#规则2-把js-放在body-末尾加载" aria-label="Permalink to &quot;规则2：把JS 放在BODY 末尾加载&quot;">​</a></h2><ul><li>因为JS 阻塞HTML解析和 CSS 染</li></ul><h2 id="规则3-不使用-css-表达式" tabindex="-1">规则3：不使用 CSS 表达式 <a class="header-anchor" href="#规则3-不使用-css-表达式" aria-label="Permalink to &quot;规则3：不使用 CSS 表达式&quot;">​</a></h2><ul><li>看似强大，实际性能开销很大，可能导致页面卡顿</li></ul><h2 id="规则4-用外链方式用css-和js" tabindex="-1">规则4：用外链方式用CSS 和JS <a class="header-anchor" href="#规则4-用外链方式用css-和js" aria-label="Permalink to &quot;规则4：用外链方式用CSS 和JS&quot;">​</a></h2><ul><li>有效减少HTML的体积可合理利用浏览器缓存</li></ul><h2 id="规则5-压缩js和css" tabindex="-1">规则5：压缩JS和CSS <a class="header-anchor" href="#规则5-压缩js和css" aria-label="Permalink to &quot;规则5：压缩JS和CSS&quot;">​</a></h2><ul><li>生产环境删除不必要的注释、空白JS 中变量名压缩，混淆压缩</li></ul><h2 id="规则6-不重复加载js" tabindex="-1">规则6：不重复加载JS <a class="header-anchor" href="#规则6-不重复加载js" aria-label="Permalink to &quot;规则6：不重复加载JS&quot;">​</a></h2><ul><li>在IE 中还是会多个请求，不能发挥缓存优势</li><li>意味着更长的JS执行时间</li></ul><h2 id="规则7-让-ajax-请求可缓存-服务端" tabindex="-1">规则7：让 Ajax 请求可缓存(服务端) <a class="header-anchor" href="#规则7-让-ajax-请求可缓存-服务端" aria-label="Permalink to &quot;规则7：让 Ajax 请求可缓存(服务端)&quot;">​</a></h2><ul><li>GZIP、内容压缩都可适用</li></ul><h2 id="规则8-用get-方式发起-ajax-请求" tabindex="-1">规则8：用GET 方式发起 Ajax 请求 <a class="header-anchor" href="#规则8-用get-方式发起-ajax-请求" aria-label="Permalink to &quot;规则8：用GET 方式发起 Ajax 请求&quot;">​</a></h2><ul><li>GET方式可以缓存</li><li>如果是获取信息，GET 更语义化</li></ul><h2 id="规则9-组件延迟加载" tabindex="-1">规则9：组件延迟加载 <a class="header-anchor" href="#规则9-组件延迟加载" aria-label="Permalink to &quot;规则9：组件延迟加载&quot;">​</a></h2><ul><li>保障关键页面资源优先加载：因为并发数限制</li><li>延迟加载的典型手段：Lazyload</li></ul><h2 id="规则10-减少dom节点数" tabindex="-1">规则10：减少DOM节点数 <a class="header-anchor" href="#规则10-减少dom节点数" aria-label="Permalink to &quot;规则10：减少DOM节点数&quot;">​</a></h2><ul><li>天猫：更多节点数以为浏览器布局、渲染时计算量更大</li></ul><h2 id="规则11-避免使用iframe" tabindex="-1">规则11：避免使用iframe <a class="header-anchor" href="#规则11-避免使用iframe" aria-label="Permalink to &quot;规则11：避免使用iframe&quot;">​</a></h2><ul><li>会阻塞父文档的 onload</li><li>即使是空白也比较耗时</li></ul><h2 id="规则12-减少-cookie-体积" tabindex="-1">规则12：减少 COOKIE 体积 <a class="header-anchor" href="#规则12-减少-cookie-体积" aria-label="Permalink to &quot;规则12：减少 COOKIE 体积&quot;">​</a></h2><ul><li>因为 COOKIE 每次请求都会全部带上</li></ul><h2 id="规则13-使用无-cookie-域名加载静态资源-后端" tabindex="-1">规则13：使用无 COOKIE 域名加载静态资源(后端) <a class="header-anchor" href="#规则13-使用无-cookie-域名加载静态资源-后端" aria-label="Permalink to &quot;规则13：使用无 COOKIE 域名加载静态资源(后端)&quot;">​</a></h2><ul><li>减少静态资源加载时的网络传输量</li><li>静态资源加载通常是不需要 COOKIE 的</li><li>阿里:精简COOKIE后，每年节省的流量TB记</li></ul><h2 id="规则14-减少js-中的dom-访问" tabindex="-1">规则14：减少JS 中的DOM 访问 <a class="header-anchor" href="#规则14-减少js-中的dom-访问" aria-label="Permalink to &quot;规则14：减少JS 中的DOM 访问&quot;">​</a></h2><ul><li>对于查找到的元素，缓存在变量中</li><li>节点增加是合理利用 DocumentFragment</li><li>不要用JS去频繁修改样式</li></ul><h2 id="规则15-使用更智能的事件监听机制" tabindex="-1">规则15：使用更智能的事件监听机制 <a class="header-anchor" href="#规则15-使用更智能的事件监听机制" aria-label="Permalink to &quot;规则15：使用更智能的事件监听机制&quot;">​</a></h2><ul><li>基于事件冒泡的委托机制，有效减少绑定的数量</li></ul><h2 id="规则16-使用常见的图片优化手段" tabindex="-1">规则16：使用常见的图片优化手段 <a class="header-anchor" href="#规则16-使用常见的图片优化手段" aria-label="Permalink to &quot;规则16：使用常见的图片优化手段&quot;">​</a></h2><ul><li>相比代码，图片体积很大</li><li>PNGCrush、JPEGTRAN、PNGQUANT</li><li>渐进式编码：JPG</li></ul><h2 id="规则17-不要在html中缩放图片" tabindex="-1">规则17：不要在HTML中缩放图片 <a class="header-anchor" href="#规则17-不要在html中缩放图片" aria-label="Permalink to &quot;规则17：不要在HTML中缩放图片&quot;">​</a></h2><ul><li>徒增渲染开销，提供适当尺寸即可</li></ul><h2 id="规则18-不要把图片-src-置空" tabindex="-1">规则18：不要把图片 SRC 置空 <a class="header-anchor" href="#规则18-不要把图片-src-置空" aria-label="Permalink to &quot;规则18：不要把图片 SRC 置空&quot;">​</a></h2><ul><li>IE、ChromeFireFox 会发起额外的主文档请求</li></ul><h2 id="规则19-任何资源尽量在-25k-以内" tabindex="-1">规则19：任何资源尽量在 25K 以内 <a class="header-anchor" href="#规则19-任何资源尽量在-25k-以内" aria-label="Permalink to &quot;规则19：任何资源尽量在 25K 以内&quot;">​</a></h2><ul><li>iPhone 无法缓存25K 以上的资源</li></ul>',39),t=[o];function h(s,u,d,n,c,m){return e(),l("div",null,t)}const _=a(r,[["render",h]]);export{q as __pageData,_ as default};
